FNePyObject_Border* NePyObjectNew_Border(UBorder* InValue, PyTypeObject* InPyType)
{
	check(PyType_IsSubtype(InPyType, &FNePyObjectType_Border));
	FNePyObject_Border* RetValue = (FNePyObject_Border*)InPyType->tp_alloc(InPyType, 0);
	RetValue->Value = InValue;
	return RetValue;
}

FNePyObject_Border* NePyObjectCheck_Border(PyObject* InPyObj)
{
	if (InPyObj && PyObject_IsInstance(InPyObj, (PyObject*)&FNePyObjectType_Border))
	{
		return (FNePyObject_Border*)InPyObj;
	}
	return nullptr;
}

PyTypeObject* NePyObjectGetType_Border()
{
	return &FNePyObjectType_Border;
}

PyTypeObject* NePyNePyWrappedClassInit_Border(const UClass* InClass, PyTypeObject* InPyBase, PyObject* InPyBases)
{
	PyTypeObject* NePyObjectType = &FNePyObjectType_Border;
	NePyObjectType_InitCommon(NePyObjectType);
	NePyObjectType->tp_getset = FNePyObjectType_Border_getset;
	NePyObjectType->tp_methods = FNePyObjectType_Border_methods;
	NePyObjectType->tp_base = InPyBase;
	NePyObjectType->tp_bases = InPyBases;
	PyType_Ready(NePyObjectType);

	FNePyObjectTypeInfo TypeInfo = {
		NePyObjectType,
		ENePyTypeFlags::StaticPyType,
		(NePyObjectNewFunc)NePyObjectNew_Border,
	};
	FNePyWrapperTypeRegistry::Get().RegisterWrappedClassType(InClass, TypeInfo);

	return NePyObjectType;
}

void NePyInitObject_Border(PyObject* PyOuterModule)
{
	FNePyWrapperInitializer::Get().RegisterWrappedClassInitFunc(
		UBorder::StaticClass(), NePyNePyWrappedClassInit_Border);
}

namespace NePyBase
{
	bool ToCpp(PyObject* InPyObj, UBorder*& OutVal)
	{
		if (FNePyObject_Border* PyObj = NePyObjectCheck_Border(InPyObj))
		{
			if (FNePyHouseKeeper::Get().IsValid(PyObj))
			{
				OutVal = PyObj->GetValue();
				return true;
			}
		}
		return false;
	}
}

